const fs = require('fs');
const path = require('path');
const home = process.env.HOME;
const ws = path.join(home, 'workspace');

function w(rel, b64) {
  const dest = path.join(ws, rel);
  fs.mkdirSync(path.dirname(dest), { recursive: true });
  fs.writeFileSync(dest, Buffer.from(b64, 'base64'));
  console.log('✓ ' + rel);
}

w('server/email.ts', '');
w('server/seo.ts', '');
w('client/src/App.tsx', '');
w('client/src/components/layout/footer.tsx', '');
w('client/src/pages/notary-bond-texas.tsx', '');
w('server/routes.ts', '');
